class MinStack:
    def __init__(self):
        self.st = []
        self.mins = []

    def push(self, x):
        self.st.append(x)
        if not self.mins or x <= self.mins[-1]:
            self.mins.append(x)
        else:
            self.mins.append(self.mins[-1])

    def pop(self):
        self.mins.pop()
        return self.st.pop()

    def top(self):
        return self.st[-1]

    def get_min(self):
        return self.mins[-1]

