class Queue:
    def __init__(self):
        self.in_st = []
        self.out_st = []

    def enqueue(self, x):
        self.in_st.append(x)

    def dequeue(self):
        if not self.out_st:
            while self.in_st:
                self.out_st.append(self.in_st.pop())
        return self.out_st.pop()
